const allItems = $input.all();

const extractItem = allItems[0]?.json || {};
const finData = extractItem.data || extractItem;

const analysisItem = allItems[1]?.json || {};
const contractAnalysis = analysisItem.answer || analysisItem.markdown || analysisItem.text || '';

const triggerData = $('New Document').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

// All fields are flat from schema
const docType          = finData.documentType   || 'Unknown';
const clientName       = finData.clientName     || 'Unknown Client';
const clientEmail      = finData.clientEmail    || 'N/A';
const hourlyRate       = parseFloat(finData.hourlyRate)    || 0;
const projectRate      = parseFloat(finData.projectRate)   || 0;
const estimatedHours   = parseFloat(finData.estimatedHours)|| 0;
const paymentTerms     = finData.paymentTerms   || 'N/A';
const depositAmount    = parseFloat(finData.depositAmount) || 0;
const startDate        = finData.startDate      || 'N/A';
const endDate          = finData.endDate        || 'N/A';
const killFeeAmount    = parseFloat(finData.killFeeAmount) || 0;
const killFeePercent   = parseFloat(finData.killFeePercent)|| 0;
const killFee          = killFeeAmount > 0 ? `$${killFeeAmount}` : (killFeePercent > 0 ? `${killFeePercent}%` : 'Not specified');
const revisionLimit    = parseInt(finData.revisionLimit)   || 0;
const invoiceNumber    = finData.invoiceNumber  || 'N/A';
const invoiceDate      = finData.invoiceDate    || 'N/A';
const dueDate          = finData.dueDate        || 'N/A';
const invoiceTotal     = parseFloat(finData.invoiceTotal)  || 0;
const paymentStatus    = finData.paymentStatus  || 'Unpaid';
const poNumber         = finData.poNumber       || 'N/A';
const lineItemSummary  = finData.lineItemsSummary || 'N/A';
const paymentDate      = finData.paymentDate    || 'N/A';
const paymentAmount    = parseFloat(finData.paymentAmount) || 0;
const paymentMethod    = finData.paymentMethod  || 'N/A';

// Key amount
let keyAmount = 0;
if (invoiceTotal > 0)                         keyAmount = invoiceTotal;
else if (projectRate > 0)                     keyAmount = projectRate;
else if (hourlyRate > 0 && estimatedHours > 0)keyAmount = hourlyRate * estimatedHours;
else if (paymentAmount > 0)                   keyAmount = paymentAmount;

// Days until due
let daysUntilDue = 'N/A';
let paymentUrgency = 'N/A';
if (dueDate && dueDate !== 'N/A') {
  try {
    const due = new Date(dueDate);
    const today = new Date();
    const diffDays = Math.ceil((due - today) / (1000 * 60 * 60 * 24));
    daysUntilDue = diffDays;
    if (paymentStatus.toLowerCase() === 'paid' || paymentStatus.toLowerCase() === 'paid in full')  paymentUrgency = '✅ PAID';
    else if (diffDays < -30) paymentUrgency = '🔴 SEVERELY OVERDUE';
    else if (diffDays < 0)   paymentUrgency = '🔴 OVERDUE';
    else if (diffDays <= 7)  paymentUrgency = '🟡 DUE SOON';
    else                     paymentUrgency = '🟢 ON TRACK';
  } catch(e) {}
}

// Risk analysis
const al = contractAnalysis.toLowerCase();
let riskLevel = 'MEDIUM';
if (al.includes('risk level: low') || al.includes('low risk'))   riskLevel = 'LOW';
else if (al.includes('risk level: high') || al.includes('high risk')) riskLevel = 'HIGH';

let riskFlags = 0;
if (al.includes('scope creep'))                                       riskFlags++;
if (killFee === 'Not specified')                                      riskFlags++;
if (al.includes('unlimited revision') || revisionLimit === 0)        riskFlags++;
if (al.includes('no late') || al.includes('no penalty'))             riskFlags++;
if (depositAmount === 0 && projectRate > 5000)                       riskFlags++;

return [{ json: {
  fileName, fileId,
  documentType:   docType,
  clientName,
  clientEmail,
  contractorName: finData.contractorName || 'N/A',
  hourlyRate,
  projectRate,
  estimatedHours,
  keyAmount,
  paymentTerms,
  depositAmount,
  startDate,
  endDate,
  killFee,
  revisionLimit,
  invoiceNumber,
  invoiceDate,
  dueDate,
  invoiceTotal,
  paymentStatus,
  poNumber,
  lineItemSummary,
  paymentDate,
  paymentAmount,
  paymentMethod,
  daysUntilDue,
  paymentUrgency,
  riskLevel,
  riskFlags,
  contractAnalysis,
  processedAt: new Date().toISOString()
}}];

